<?php
declare(strict_types=1);
if($path!=='/admin/tag-groups')return;if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}
if($method==='POST'){verify_csrf();$action=post('action');if($action==='create'){db()->prepare('INSERT INTO tag_groups(name,position) VALUES(?,?)')->execute([trim(post('name')),(int)post('position')]);audit('create','tag_group',(int)db()->lastInsertId());}elseif($action==='assign'){db()->prepare('UPDATE tags SET tag_group_id=? WHERE id=?')->execute([(int)post('tag_group_id')?:null,(int)post('tag_id')]);audit('update','tag',(int)post('tag_id'),['tag_group_id'=>(int)post('tag_group_id')]);}flash('success','Tag organization updated.');redirect('/admin/tag-groups');}
$groups=db()->query('SELECT * FROM tag_groups ORDER BY position,name')->fetchAll();$tags=all_tags();layout('Tag groups',function()use($groups,$tags){?><div class="actions"><h1 style="margin:0">Tag groups</h1><span class="spacer"></span><a class="btn secondary" href="/admin/tags">Manage tags</a><a class="btn secondary" href="/admin/settings">Settings</a></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="create"><h2>Create group</h2><div class="form-grid"><label>Name<input name="name" required></label><label>Sort position<input type="number" name="position" value="100"></label></div><button>Create group</button></form><div class="card"><h2>Assign tags to groups</h2><table><thead><tr><th>Tag</th><th>Group</th><th></th></tr></thead><tbody><?php foreach($tags as $t):?><tr><td><span class="tag" style="background:<?=e($t['color'])?>"><?=e($t['name'])?></span></td><td><form method="post" class="actions"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="assign"><input type="hidden" name="tag_id" value="<?=$t['id']?>"><select name="tag_group_id"><option value="">Ungrouped</option><?php foreach($groups as $g):?><option value="<?=$g['id']?>" <?=$t['tag_group_id']==$g['id']?'selected':''?>><?=e($g['name'])?></option><?php endforeach?></select><button>Assign</button></form></td><td><?=e($t['group_name']??'Ungrouped')?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
